// // This module implements a 4-bit DRAM cell with read and write operations. The data input (D) is stored in the cell on the falling edge of the clock when WE is high, and the data stored in the cell is output on Q on the falling edge of the clock when WE is low.
module dram_cell (  
    input wire [3:0] D,  
    input wire WE,  
    input wire CLK,  
    output reg [3:0] Q  
);  
    reg [3:0] storage;  

    always @(posedge CLK) begin  
        if (WE)  
            storage <= D;  
        else  
            Q <= storage;  
    end  
endmodule
